export interface LlmaEvaluationCreateParams {
    /** Trigger conditions that filter which events are evaluated. OR between condition sets, AND within each. Each set is {id, rollout_percentage, properties[]} — `rollout_percentage` (0-100, defaults to 100) is the sampling field the dispatcher reads. */
    conditions?: Array<{
        /** Stable identifier for this condition set. */
        id: string
        /** Property filters (event or person) that scope which generations match this condition set. */
        properties?: Array<Record<string, unknown>>
        /** Percentage (0-100) of matching events to sample for this evaluation. Defaults to 100. */
        rollout_percentage?: number
    }>
    /** Set to true to soft-delete the evaluation. */
    deleted?: boolean
    /** Optional description of what this evaluation checks. */
    description?: string
    /** Whether the evaluation runs automatically on new $ai_generation events. */
    enabled?: boolean
    /** Configuration dict. For 'llm_judge': {prompt}; for 'hog': {source}; for 'sentiment': {source: 'user_messages'}. */
    evaluation_config?:
        | {
              /** Evaluation criteria for the LLM judge. Describe what makes a good vs bad response. */
              prompt: string
          }
        | {
              /** Hog source code. Must return true (pass), false (fail), or null for N/A. */
              source: string
          }
        | {
              /** Classify sentiment from user messages in the generation input. */
              source?: 'user_messages'
          }
    /** 'llm_judge' uses an LLM to score outputs against a prompt; 'hog' runs deterministic Hog code; 'sentiment' classifies user-message sentiment. * `llm_judge` - LLM as a judge * `hog` - Hog * `sentiment` - Sentiment analysis */
    evaluation_type: 'llm_judge' | 'hog' | 'sentiment'
    model_configuration?: {
        model: string
        /** * `openai` - Openai * `anthropic` - Anthropic * `gemini` - Gemini * `openrouter` - Openrouter * `fireworks` - Fireworks * `azure_openai` - Azure OpenAI * `together_ai` - Together AI * `minimax` - MiniMax */
        provider:
            | 'openai'
            | 'anthropic'
            | 'gemini'
            | 'openrouter'
            | 'fireworks'
            | 'azure_openai'
            | 'together_ai'
            | 'minimax'
        /** Team provider key to run this eval with (same provider as `provider`). Leave null only for brief pre-key testing; real evals should set it. */
        provider_key_id?: string | null
        provider_key_name?: string | null
    } | null
    /** Name of the evaluation. */
    name: string
    /** Output config. For 'boolean' output_type: {allows_na} to permit N/A results. */
    output_config?: {
        /** Whether the evaluation can return N/A for non-applicable generations. */
        allows_na?: boolean
    }
    /** Output format. Use 'boolean' for pass/fail evaluations and 'sentiment' for sentiment analysis. * `boolean` - Boolean (Pass/Fail) * `sentiment` - Sentiment */
    output_type: 'boolean' | 'sentiment'
    /** What the evaluation runs on. 'generation' evaluates each matching $ai_generation event individually. 'trace' evaluates the whole trace once: the first matching generation schedules a run that waits for the trace to settle, then evaluates all of its events together. Condition filters still match individual generations — a trace is evaluated when any of its generations matches, and sampling applies per trace. * `generation` - Generation * `trace` - Trace */
    target?: 'generation' | 'trace'
    /** Target-specific config. For 'trace' target: {window_seconds}. Empty for 'generation'. */
    target_config?: {
        /** For 'trace' target: seconds to wait after the first matching generation before evaluating the whole trace. Captured when the run is scheduled — editing it does not change trace runs already in flight. */
        window_seconds?: number
    }
}

