export interface LogsAlertsDestinationsCreateParams {
    /** A UUID string identifying this logs alert configuration. */
    id: string
    /** Slack channel ID. Required when type=slack. */
    slack_channel_id?: string
    /** Human-readable channel name for display. */
    slack_channel_name?: string
    /** Integration ID for the Slack workspace. Required when type=slack. */
    slack_workspace_id?: number
    /** Destination type — slack, webhook, or teams. * `slack` - slack * `webhook` - webhook * `teams` - teams */
    type: 'slack' | 'webhook' | 'teams'
    /** HTTPS endpoint to POST to. Required when type=webhook, or the Teams webhook URL when type=teams. */
    webhook_url?: string
}

export interface LogsAlertsDestinationsDeleteCreateParams {
    /** HogFunction IDs to delete as one atomic destination group. */
    hog_function_ids: Array<string>
    /** A UUID string identifying this logs alert configuration. */
    id: string
}

export interface MarketingAnalyticsDataSourcesParams {
    /** Optional. Restrict to one integration (e.g. 'GoogleAds'). */
    source_type?: string | null
}

export interface MarketingAnalyticsDiagnoseParams {
    /** Lookback window for attribution health (1-365 days); defaults to 7 */
    attribution_lookback_days?: number
    /** Whether to include the conversion-goal summary in the diagnostic */
    include_conversion_goals?: boolean
    /** Optional integration filter */
    source_type?: string | null
}

